                    {"type": "quiz", "question": "Опечатка на главной странице, которую видят все пользователи. Какие Severity и Priority?", "options": [{"id": "a", "text": "Severity: Trivial, Priority: High", "correct": True}, {"id": "b", "text": "Severity: Critical, Priority: High", "correct": False}, {"id": "c", "text": "Severity: Trivial, Priority: Low", "correct": False}, {"id": "d", "text": "Severity: Blocker, Priority: High", "correct": False}]},
